"use client";

import * as React from "react";
import {
  IconMapPin,
  IconFlag,
  IconPlane,
  IconBuildingSkyscraper,
} from "@tabler/icons-react";
import {
  AmountBreakdown,
  Badge,
  BottomActionBar,
  Button,
  Card,
  CardContent,
  DatePicker,
  Input,
  Label,
  ListCard,
  NumberInput,
  PageHeader,
  RadioCard,
  RadioCardGroup,
  Select,
  Separator,
  Stepper,
  type StepperStep,
  TimePicker,
  ToggleGroup,
  ToggleGroupItem,
} from "@gunjo/ui";

import {
  AIRPORT_FLAT_FARES,
  BOOKING_TYPES,
  CHARTER_COURSES,
  DISPATCH_FEE,
  JPY,
  PLACE_SUGGESTIONS,
  RESERVATION_FEE,
  SCHEDULE_BASE_ESTIMATE,
  TIME_WINDOWS,
  VEHICLES,
  type BookingType,
  dispatchEta,
  formatJaDate,
  formatJaDateTime,
  makeBookingNo,
} from "./data";
import { Confirmation, type ConfirmedBooking } from "./Confirmation";

type StepKey = "type" | "place" | "when" | "vehicle" | "confirm";
const STEP_ORDER: StepKey[] = ["type", "place", "when", "vehicle", "confirm"];
const STEP_LABELS: Record<StepKey, string> = {
  type: "予約タイプ",
  place: "場所",
  when: "日時",
  vehicle: "車種",
  confirm: "確認",
};

// 既存の今後の予約（予約一覧のための既存データ）。
const EXISTING_UPCOMING: ConfirmedBooking[] = [
  {
    bookingNo: "GT-480231",
    typeLabel: "空港定額",
    pickup: "港区 麻布十番",
    dropoff: "羽田空港 (HND)",
    whenLabel: "7月3日(金) 6時10分",
    vehicleName: "ジャパンタクシー（黒タク）",
    passengers: 2,
    dispatchEta: "06:00",
    totalLabel: JPY.format(6200),
  },
];

export default function TaxiBookingPage() {
  const [stepIdx, setStepIdx] = React.useState(0);
  const step = STEP_ORDER[stepIdx];

  // フォーム状態
  const [bookingType, setBookingType] = React.useState<BookingType>("schedule");
  const [pickup, setPickup] = React.useState("");
  const [dropoff, setDropoff] = React.useState("");
  const [via, setVia] = React.useState("");
  const [showVia, setShowVia] = React.useState(false);
  const [airportArea, setAirportArea] = React.useState(AIRPORT_FLAT_FARES[0].area);
  const [airportName, setAirportName] = React.useState(AIRPORT_FLAT_FARES[0].airport);
  const [airportDir, setAirportDir] = React.useState<"toAirport" | "fromAirport">("toAirport");
  const [charterCourse, setCharterCourse] = React.useState(CHARTER_COURSES[0].value);

  const [date, setDate] = React.useState<Date | undefined>(undefined);
  const [time, setTime] = React.useState("");
  const [timeWindow, setTimeWindow] = React.useState("exact");

  const [vehicle, setVehicle] = React.useState(VEHICLES[0].value);
  const [passengers, setPassengers] = React.useState(1);
  const [luggage, setLuggage] = React.useState(0);

  const [confirmed, setConfirmed] = React.useState<ConfirmedBooking | null>(null);

  const today = React.useMemo(() => {
    const d = new Date();
    d.setHours(0, 0, 0, 0);
    return d;
  }, []);

  // ---- 料金計算 ----
  const vehicleOpt = VEHICLES.find((v) => v.value === vehicle) ?? VEHICLES[0];

  const flatFare = React.useMemo(() => {
    const row = AIRPORT_FLAT_FARES.find(
      (f) => f.area === airportArea && f.airport === airportName,
    );
    return Math.round((row?.fare ?? 0) * vehicleOpt.fareMultiplier);
  }, [airportArea, airportName, vehicleOpt.fareMultiplier]);

  const charterFare = React.useMemo(() => {
    const c = CHARTER_COURSES.find((x) => x.value === charterCourse) ?? CHARTER_COURSES[0];
    return Math.round(c.basePrice * vehicleOpt.fareMultiplier);
  }, [charterCourse, vehicleOpt.fareMultiplier]);

  const scheduleEstimate = React.useMemo(
    () => Math.round(SCHEDULE_BASE_ESTIMATE * vehicleOpt.fareMultiplier),
    [vehicleOpt.fareMultiplier],
  );

  // 合計目安（タイプ別）
  const total = React.useMemo(() => {
    if (bookingType === "airport") return flatFare;
    if (bookingType === "charter") return charterFare + RESERVATION_FEE;
    return scheduleEstimate + RESERVATION_FEE + DISPATCH_FEE;
  }, [bookingType, flatFare, charterFare, scheduleEstimate]);

  const breakdownLines = React.useMemo(() => {
    if (bookingType === "airport") {
      return [
        {
          label: "定額運賃",
          amount: flatFare,
          note: `${airportArea} ⇄ ${airportName}・${vehicleOpt.name}`,
        },
      ];
    }
    if (bookingType === "charter") {
      const c = CHARTER_COURSES.find((x) => x.value === charterCourse) ?? CHARTER_COURSES[0];
      return [
        { label: `貸切料金（${c.label}）`, amount: charterFare, note: vehicleOpt.name },
        { label: "予約料金", amount: RESERVATION_FEE },
      ];
    }
    return [
      { label: "運賃の見積もり", amount: scheduleEstimate, note: "メーター運賃の目安" },
      { label: "予約料金", amount: RESERVATION_FEE },
      { label: "迎車料金", amount: DISPATCH_FEE },
    ];
  }, [bookingType, flatFare, charterFare, scheduleEstimate, airportArea, airportName, charterCourse, vehicleOpt.name]);

  // ---- ステップ毎の入力完了判定 ----
  const placeValid =
    bookingType === "airport" ? Boolean(airportArea && airportName) : Boolean(pickup && dropoff);
  const whenValid = Boolean(date && time);

  const canAdvance = React.useMemo(() => {
    switch (step) {
      case "type":
        return Boolean(bookingType);
      case "place":
        return placeValid;
      case "when":
        return whenValid;
      case "vehicle":
        return Boolean(vehicle) && passengers >= 1;
      case "confirm":
        return placeValid && whenValid;
      default:
        return false;
    }
  }, [step, bookingType, placeValid, whenValid, vehicle, passengers]);

  const steps: StepperStep[] = STEP_ORDER.map((k, i) => ({
    label: STEP_LABELS[k],
    state: i < stepIdx ? "completed" : i === stepIdx ? "current" : "upcoming",
  }));

  // ---- 表示用ラベル ----
  const effectivePickup =
    bookingType === "airport"
      ? airportDir === "toAirport"
        ? airportArea
        : airportName
      : pickup;
  const effectiveDropoff =
    bookingType === "airport"
      ? airportDir === "toAirport"
        ? airportName
        : airportArea
      : dropoff;

  const whenLabel = date && time ? formatJaDateTime(date, time) : "日時未指定";
  const windowLabel = TIME_WINDOWS.find((w) => w.value === timeWindow)?.label ?? "";

  // ---- ナビゲーション ----
  function goNext() {
    if (step === "confirm") {
      handleConfirm();
      return;
    }
    if (canAdvance) setStepIdx((i) => Math.min(i + 1, STEP_ORDER.length - 1));
  }
  function goBack() {
    setStepIdx((i) => Math.max(i - 1, 0));
  }

  function handleConfirm() {
    const seed = Math.floor((date?.getTime() ?? Date.now()) / 1000) + passengers;
    setConfirmed({
      bookingNo: makeBookingNo(seed),
      typeLabel: BOOKING_TYPES.find((t) => t.value === bookingType)?.title ?? "",
      pickup: effectivePickup || "乗車地",
      dropoff: effectiveDropoff || "降車地",
      whenLabel: `${whenLabel}${windowLabel && timeWindow !== "exact" ? `（${windowLabel}）` : ""}`,
      vehicleName: vehicleOpt.name,
      passengers,
      dispatchEta: time ? dispatchEta(time) : "--:--",
      totalLabel: JPY.format(total),
    });
  }

  function resetAll() {
    setConfirmed(null);
    setStepIdx(0);
  }

  // ===== 確定後の画面 =====
  if (confirmed) {
    return (
      <main className="mx-auto flex min-h-dvh w-full max-w-md flex-col bg-background">
        <PageHeader title="予約完了" subtitle="群青タクシー" align="center" />
        <div className="flex-1">
          <Confirmation booking={confirmed} upcoming={EXISTING_UPCOMING} onReset={resetAll} />
        </div>
      </main>
    );
  }

  const isLastStep = step === "confirm";
  const ctaLabel = isLastStep ? "この内容で予約する" : "次へ";

  return (
    <main className="mx-auto flex min-h-dvh w-full max-w-md flex-col bg-background">
      <PageHeader
        title="タクシーを予約"
        subtitle="群青タクシー・予約配車／空港定額"
        align="center"
        onBack={stepIdx > 0 ? goBack : undefined}
        backLabel="前の手順へ戻る"
      />

      {/* ステッパー（進捗） */}
      <div className="border-b border-border bg-background">
        <Stepper steps={steps} aria-label="予約の手順" className="px-2 py-3" />
      </div>

      <div className="flex-1 overflow-y-auto px-4 py-5 pb-6">
        {/* ========== STEP 1: 予約タイプ ========== */}
        {step === "type" && (
          <Section
            title="予約タイプを選ぶ"
            description="ご利用方法を選んでください。選んだタイプによって入力項目が変わります。"
          >
            <RadioCardGroup
              value={bookingType}
              onValueChange={(v) => setBookingType(v as BookingType)}
              aria-label="予約タイプ"
            >
              {BOOKING_TYPES.map((t) => (
                <RadioCard
                  key={t.value}
                  value={t.value}
                  title={t.title}
                  description={t.description}
                  tags={t.badge ? <Badge variant="info">{t.badge}</Badge> : undefined}
                />
              ))}
            </RadioCardGroup>
          </Section>
        )}

        {/* ========== STEP 2: 場所 ========== */}
        {step === "place" && (
          <Section
            title="乗車地・降車地"
            description={
              bookingType === "airport"
                ? "空港と都内エリアを選ぶと、定額運賃が適用されます。"
                : "出発地と目的地を入力してください。経由地は任意です。"
            }
          >
            {bookingType === "airport" ? (
              <div className="flex flex-col gap-4">
                <fieldset className="flex flex-col gap-2">
                  <legend className="mb-1 text-sm font-medium text-foreground">移動の向き</legend>
                  <ToggleGroup
                    type="single"
                    value={airportDir}
                    onValueChange={(v) => v && setAirportDir(v as "toAirport" | "fromAirport")}
                    variant="outline"
                    disallowEmpty
                    aria-label="移動の向き"
                    className="grid grid-cols-2 gap-2"
                  >
                    <ToggleGroupItem value="toAirport" className="w-full">
                      エリア → 空港
                    </ToggleGroupItem>
                    <ToggleGroupItem value="fromAirport" className="w-full">
                      空港 → エリア
                    </ToggleGroupItem>
                  </ToggleGroup>
                </fieldset>
                <Select
                  label="エリア"
                  value={airportArea}
                  onChange={(e) => setAirportArea(e.target.value)}
                >
                  {[...new Set(AIRPORT_FLAT_FARES.map((f) => f.area))].map((a) => (
                    <option key={a} value={a}>
                      {a}
                    </option>
                  ))}
                </Select>
                <Select
                  label="空港"
                  value={airportName}
                  onChange={(e) => setAirportName(e.target.value)}
                >
                  {[...new Set(AIRPORT_FLAT_FARES.map((f) => f.airport))].map((a) => (
                    <option key={a} value={a}>
                      {a}
                    </option>
                  ))}
                </Select>
                <Card>
                  <CardContent className="flex items-center gap-3 p-3">
                    <IconPlane className="size-5 shrink-0 text-primary" aria-hidden="true" />
                    <p className="text-sm text-foreground">
                      <span className="font-medium">
                        {airportDir === "toAirport" ? airportArea : airportName}
                      </span>
                      <span className="mx-1 text-muted-foreground">→</span>
                      <span className="font-medium">
                        {airportDir === "toAirport" ? airportName : airportArea}
                      </span>
                    </p>
                  </CardContent>
                </Card>
              </div>
            ) : (
              <div className="flex flex-col gap-4">
                <PlaceField
                  id="pickup"
                  label="乗車地"
                  icon={<IconMapPin className="size-4 text-success-strong" aria-hidden="true" />}
                  placeholder="例：渋谷駅 ハチ公口"
                  value={pickup}
                  onChange={setPickup}
                />
                {showVia && (
                  <PlaceField
                    id="via"
                    label="経由地（任意）"
                    icon={<IconMapPin className="size-4 text-muted-foreground" aria-hidden="true" />}
                    placeholder="例：表参道"
                    value={via}
                    onChange={setVia}
                  />
                )}
                <PlaceField
                  id="dropoff"
                  label="降車地"
                  icon={<IconFlag className="size-4 text-destructive" aria-hidden="true" />}
                  placeholder="例：港区 六本木ヒルズ"
                  value={dropoff}
                  onChange={setDropoff}
                />
                {!showVia && (
                  <Button
                    variant="ghost"
                    size="sm"
                    className="self-start"
                    onClick={() => setShowVia(true)}
                  >
                    ＋ 経由地を追加
                  </Button>
                )}
                <div className="flex flex-wrap gap-2 pt-1">
                  {PLACE_SUGGESTIONS.map((s) => (
                    <Button
                      key={s}
                      type="button"
                      variant="outline"
                      size="sm"
                      onClick={() => (pickup ? setDropoff(s) : setPickup(s))}
                    >
                      {s}
                    </Button>
                  ))}
                </div>
              </div>
            )}
          </Section>
        )}

        {/* ========== STEP 3: 日時 ========== */}
        {step === "when" && (
          <Section
            title="乗車日時を指定"
            description="ご希望の日付と時刻を選んでください。時刻には幅を指定できます。"
          >
            <div className="flex flex-col gap-5">
              <div className="flex flex-col gap-1.5">
                <Label htmlFor="ride-date">乗車日</Label>
                <DatePicker
                  id="ride-date"
                  value={date}
                  onValueChange={setDate}
                  placeholder="日付を選ぶ"
                  dateFormat="yyyy年M月d日"
                  disabledDates={{ before: today }}
                  startMonth={today}
                  calendarLabel="乗車日を選ぶ"
                  triggerClassName="w-full"
                />
                {date && (
                  <p className="text-xs text-muted-foreground">{formatJaDate(date)} を選択中</p>
                )}
              </div>

              <fieldset className="flex flex-col gap-2">
                <legend className="mb-1 text-sm font-medium text-foreground">乗車時刻</legend>
                <TimePicker
                  value={time}
                  onValueChange={setTime}
                  minuteStep={5}
                  label="乗車時刻"
                  hourLabel="時"
                  minuteLabel="分"
                />
              </fieldset>

              <fieldset className="flex flex-col gap-2">
                <legend className="mb-1 text-sm font-medium text-foreground">
                  時刻の幅（時間指定）
                </legend>
                <ToggleGroup
                  type="single"
                  value={timeWindow}
                  onValueChange={(v) => v && setTimeWindow(v as string)}
                  variant="outline"
                  disallowEmpty
                  aria-label="時刻の幅"
                  className="grid grid-cols-3 gap-2"
                >
                  {TIME_WINDOWS.map((w) => (
                    <ToggleGroupItem key={w.value} value={w.value} className="w-full">
                      {w.label}
                    </ToggleGroupItem>
                  ))}
                </ToggleGroup>
                <p className="text-xs text-muted-foreground">
                  幅を指定すると、混雑時でも配車が成立しやすくなります。
                </p>
              </fieldset>

              {date && time && (
                <Card>
                  <CardContent className="flex items-center gap-3 p-3">
                    <IconBuildingSkyscraper
                      className="size-5 shrink-0 text-primary"
                      aria-hidden="true"
                    />
                    <div className="text-sm">
                      <p className="font-medium text-foreground">
                        {formatJaDateTime(date, time)}
                        {timeWindow !== "exact" ? `（${windowLabel}）` : ""}
                      </p>
                      <p className="text-xs text-muted-foreground">
                        配車予定 {dispatchEta(time)} 頃にお迎え
                      </p>
                    </div>
                  </CardContent>
                </Card>
              )}
            </div>
          </Section>
        )}

        {/* ========== STEP 4: 車種・人数 ========== */}
        {step === "vehicle" && (
          <Section title="車種・人数" description="ご利用人数とお荷物に合わせて車種をお選びください。">
            <div className="flex flex-col gap-5">
              <RadioCardGroup value={vehicle} onValueChange={setVehicle} aria-label="車種">
                {VEHICLES.map((v) => {
                  const price =
                    bookingType === "airport"
                      ? Math.round(
                          (AIRPORT_FLAT_FARES.find(
                            (f) => f.area === airportArea && f.airport === airportName,
                          )?.fare ?? 0) * v.fareMultiplier,
                        )
                      : bookingType === "charter"
                        ? Math.round(
                            (CHARTER_COURSES.find((c) => c.value === charterCourse)?.basePrice ??
                              0) * v.fareMultiplier,
                          )
                        : Math.round(SCHEDULE_BASE_ESTIMATE * v.fareMultiplier);
                  return (
                    <RadioCard
                      key={v.value}
                      value={v.value}
                      title={v.name}
                      description={v.detail}
                      tags={v.tags?.map((t) => (
                        <Badge key={t} variant={t === "人気" ? "info" : "secondary"}>
                          {t}
                        </Badge>
                      ))}
                      price={JPY.format(price)}
                      highlight={
                        bookingType === "airport" ? "定額・追加料金なし" : `${v.capacity}・荷物OK`
                      }
                    />
                  );
                })}
              </RadioCardGroup>

              <Separator />

              <div className="grid grid-cols-2 gap-4">
                <NumberInput
                  label="ご乗車人数"
                  layout="stepper"
                  value={passengers}
                  onValueChange={setPassengers}
                  min={1}
                  max={9}
                  incrementLabel="人数を増やす"
                  decrementLabel="人数を減らす"
                />
                <NumberInput
                  label="お荷物（個）"
                  layout="stepper"
                  value={luggage}
                  onValueChange={setLuggage}
                  min={0}
                  max={9}
                  incrementLabel="荷物を増やす"
                  decrementLabel="荷物を減らす"
                />
              </div>
            </div>
          </Section>
        )}

        {/* ========== STEP 5: 確認 ========== */}
        {step === "confirm" && (
          <Section title="予約内容の確認" description="内容をご確認のうえ、予約を確定してください。">
            <div className="flex flex-col gap-4">
              <ListCard
                leading={<IconMapPin className="size-5 text-success-strong" aria-hidden="true" />}
                title={effectivePickup || "乗車地未設定"}
                description="乗車地"
                onSelect={() => setStepIdx(1)}
              />
              <ListCard
                leading={<IconFlag className="size-5 text-destructive" aria-hidden="true" />}
                title={effectiveDropoff || "降車地未設定"}
                description="降車地"
                onSelect={() => setStepIdx(1)}
              />
              <ListCard
                title={whenLabel}
                description={`乗車日時${timeWindow !== "exact" ? `・${windowLabel}` : ""}`}
                meta={`配車予定 ${time ? dispatchEta(time) : "--:--"}`}
                onSelect={() => setStepIdx(2)}
              />
              <ListCard
                title={vehicleOpt.name}
                description={`${passengers}名・荷物${luggage}個`}
                tags={<Badge variant="secondary">{BOOKING_TYPES.find((t) => t.value === bookingType)?.title}</Badge>}
                onSelect={() => setStepIdx(3)}
              />

              <Separator />

              <Card>
                <CardContent className="p-4">
                  <AmountBreakdown
                    lines={breakdownLines}
                    total={{ label: "合計目安（税込）", amount: total }}
                    formula={
                      bookingType === "schedule"
                        ? "高速代は実費別途。深夜割増は乗車時に加算されます。"
                        : bookingType === "airport"
                          ? "定額運賃。高速代・有料道路代は実費別途精算です。"
                          : "貸切時間を超過した場合は延長料金が発生します。"
                    }
                  />
                </CardContent>
              </Card>

              <div className="flex items-center justify-between rounded-lg border border-border bg-card px-4 py-3">
                <span className="text-sm text-muted-foreground">お支払い</span>
                <span className="text-sm font-medium text-foreground">
                  アプリ決済（登録カード）
                </span>
              </div>
            </div>
          </Section>
        )}
      </div>

      {/* 常時表示のアクションバー（CTA＋合計目安） */}
      <BottomActionBar
        maxWidth="md"
        actions={
          <Button
            variant="primary"
            size="lg"
            onClick={goNext}
            disabled={!canAdvance}
            className="px-6"
          >
            {ctaLabel}
          </Button>
        }
      >
        <div className="flex flex-col">
          <span className="text-xs text-muted-foreground">
            {isLastStep ? "合計目安" : `${STEP_LABELS[step]}・合計目安`}
          </span>
          <span className="text-lg font-bold tabular-nums text-foreground">
            {JPY.format(total)}
          </span>
        </div>
      </BottomActionBar>
    </main>
  );
}

// ---- ローカルの小さなセクション見出し（@gunjo/ui に該当なし）----
function Section({
  title,
  description,
  children,
}: {
  title: string;
  description?: string;
  children: React.ReactNode;
}) {
  return (
    <section className="flex flex-col gap-3" aria-label={title}>
      <header className="flex flex-col gap-1">
        <h2 className="text-lg font-semibold text-foreground">{title}</h2>
        {description && <p className="text-sm text-muted-foreground">{description}</p>}
      </header>
      {children}
    </section>
  );
}

// ---- 乗車地/降車地の入力行（Input + アイコンの薄いラッパ）----
function PlaceField({
  id,
  label,
  icon,
  placeholder,
  value,
  onChange,
}: {
  id: string;
  label: string;
  icon: React.ReactNode;
  placeholder: string;
  value: string;
  onChange: (v: string) => void;
}) {
  return (
    <div className="flex flex-col gap-1.5">
      <Label htmlFor={id}>{label}</Label>
      <div className="flex items-center gap-2">
        <span className="flex size-9 shrink-0 items-center justify-center rounded-md bg-muted">
          {icon}
        </span>
        <Input
          id={id}
          value={value}
          placeholder={placeholder}
          onChange={(e) => onChange(e.target.value)}
          className="flex-1"
        />
      </div>
    </div>
  );
}

"use client";

import { IconCircleCheck } from "@tabler/icons-react";
import {
  Badge,
  Button,
  Card,
  CardContent,
  ListCard,
