// 「○月○日(曜) ○時○分」の和文整形。
const WEEKDAYS = ["日", "月", "火", "水", "木", "金", "土"];
export function formatJaDateTime(date: Date, time: string): string {
  const m = date.getMonth() + 1;
  const d = date.getDate();
  const w = WEEKDAYS[date.getDay()];
  const [hh, mm] = time.split(":");
  return `${m}月${d}日(${w}) ${hh}時${mm}分`;
}

export function formatJaDate(date: Date): string {
  const m = date.getMonth() + 1;
  const d = date.getDate();
  const w = WEEKDAYS[date.getDay()];
  return `${m}月${d}日(${w})`;
}

// 配車予定時刻（乗車の10分前に到着予定、という体）。
export function dispatchEta(time: string): string {
  const [hh, mm] = time.split(":").map(Number);
  const total = hh * 60 + mm - 10;
  const eh = Math.floor(((total % 1440) + 1440) % 1440 / 60);
  const em = ((total % 60) + 60) % 60;
  return `${String(eh).padStart(2, "0")}:${String(em).padStart(2, "0")}`;
}

// 予約番号の生成（決定論的に1つ作る）。
export function makeBookingNo(seed: number): string {
  const n = (seed % 900000) + 100000;
  return `GT-${n}`;
}
